export class TaxError extends Error {
  code: string;

  constructor(message: string, code: string) {
    super(message);
    this.code = code;
    this.name = "TaxError";
  }
}

/**
 * Calculates tax based on income using flat-rate brackets:
 *   income <= 0         → throw INVALID_INCOME
 *   0 < income < 10000  → 0%
 *   10000 <= income <= 50000  → 10%
 *   50001 <= income <= 150000 → 25%
 *   income > 150000     → 40%
 */
export function calculateTax(income: number): number {
  if (income <= 0) {
    throw new TaxError("Income must be a positive number", "INVALID_INCOME");
  }

  if (income < 10_000) {
    return 0;
  }

  if (income <= 50_000) {
    return income * 0.10;
  }

  if (income <= 150_000) {
    return income * 0.25;
  }

  return income * 0.40;
}

